 public void headerValidation (String filePath ,String expectedHeader, int linesToBeRead){
   String line = "";
   boolean isValid = false;
   List finalHeaders = new ArrayList();
   int lineCount = 0;
   StringBuilder headerBuilder = new StringBuilder();
   BufferedReader reader = null;

   try {
     reader = new BufferedReader(new FileReader(filePath));
     while ((line = reader.readLine()) != null) {

       if (lineCount == 0) {
         lineCount++;
         continue;
       }

       if (lineCount <= linesToBeRead) {
         headerBuilder.append(line).append("\n");
       } else {
         break;
       }
       lineCount++;
     }
     if (!headerBuilder.toString().isEmpty()) {
       for (String h : headerBuilder.toString().replaceAll("\\r?\\n", " ").replaceAll("\\s+", " ").trim().split("\\s*,\\s*")) {
         finalHeaders.add(h.replaceAll("^\"+|\"+$", "").trim());
       }
     }
     //  normalize both
     String finalHeader = Util.listToCsv(finalHeaders).replaceAll("\\s*,\\s*", ",").trim();
     String expected = expectedHeader.replaceAll("\\s*,\\s*", ",").trim();
     log.error("EXPECTED HEADER  :: " + expected);
     log.error("ACTUAL HEADER  :: " + finalHeader);
     if (expected.equalsIgnoreCase(finalHeader)) {
       isValid = true;
     }
   } catch (Exception ex) {
     throw new sailpoint.tools.GeneralException("Error while validating header", ex);

   } finally {
     try {
       if (reader != null) reader.close();
     } catch (Exception e) {
       // ignore
     }
   }
   log.error("isValid :"+isValid);
   if (!isValid) {
     throw new sailpoint.tools.GeneralException("The header in the TRE-TCR file  "+filePath+"   has been changed. Please upload the correct file.");
   }
 }


 public Map readFileAndReturnList(String inputfileName, int skipLines, String stringToAppend) {
   log.error("enter into readFileAndReturnList method");
   String h=(String)application.getAttributes().getMap().get("file");
   int index=h.lastIndexOf("\\");
   String basePath=h.substring(0,(index+1));

   String inputfile = basePath+inputfileName;
   BufferedReader grpIn = null;
   Map map = new HashMap();
   String expectedHeader = "User ID, User Name, Levels of Access, Location, Active, Logged On, Last Logon Date, Last Logon Time";
   //  User ID, User Name, Levels of Access, Location, Active, Logged On, Last Logon Date, Last Logon

   headerValidation(inputfile, expectedHeader, skipLines);
   // log.error("isHeaderValid :" +isHeaderValid);

   try {
     grpIn = new BufferedReader(new FileReader(inputfile));
     //logger.error("Opening of input file");
     String rawStr;
     int count =0;

     while ((rawStr = grpIn.readLine()) != null) {
       if(count>skipLines && !rawStr.contains("Number")) {
        // logger.error("Opening the input file");

         String records = null;               				
         RFC4180LineParser csvParser = new RFC4180LineParser(',');
         ArrayList arl = new ArrayList();
         arl = csvParser.parseLine(rawStr);
         String key = arl.get(0);
         key = key.replace("SSCDIRECT\\","");
         String entValue = arl.get(2);
         if(entValue!=null && !entValue.contains("SSCDIRECT\\")) {
           entValue ="SSCDIRECT\\" +entValue;
         }
         String value = key+","+ entValue+","+arl.get(4)+","+arl.get(6);
         value = value.replace("SSCDIRECT",stringToAppend);
         //logger.error("The value of count is incremented by 1");
         if(map.containsKey(key)) {
           List curentLst = map.get(key);
           curentLst.add(value);
           map.put(key,curentLst);
         } else {
           List newList = new ArrayList();
           newList.add(value);
           map.put(key,newList);
         }

       }count++;
     }
   } 
   catch (Exception e) 
   {
     logger.error("Error while reading file: " + inputfileName, e);
     // throw new sailpoint.tools.GeneralException(e);
     e.printStackTrace();
   }
   finally
   {
     if (grpIn != null) grpIn.close();
     logger.error("Closing the inputfile");
   }  
   log.error("exit into readFileAndReturnList method");
   return map;

 }





 logger.error("Entered into  the before customobject  TRE-TCR-Daily Pre Iterate rule");
 Custom customObj = context.getObject(Custom.class, "Custom-Delimited Application Files");

 String h,target,basePath;
 int index=0;
 List lst = null;
 Map dailyFile= null;
 Map monthlyFile=null;

 if(customObj!=null){
   h=(String)application.getAttributes().getMap().get("file");
   index=h.lastIndexOf("\\");
